        -- (tec_cod_vigencia = 1 --> 0) Marcar como no vigentes registros con match y alguna diferencia. fec_negocio - 1 día (o mismo día si coincide inicio)
        merge into {{ this }} t
        using (
            select
                tec_des_empresa,
                HASH(TIMESTAMP, DOCUMENT_NO, LINE_NO, SELL_TO_CUSTOMER_NO, SELLTO_CUSTOMER_NO, TYPE, NO, LOCATION_CODE, POSTING_GROUP, SHIPMENT_DATE, DESCRIPTION, DESCRIPTION_2, UNIT_OF_MEASURE, QUANTITY, UNIT_PRICE, UNIT_COST_LCY, VAT, LINE_DISCOUNT, LINE_DISCOUNT_AMOUNT, AMOUNT, AMOUNT_INCLUDING_VAT, ALLOW_INVOICE_DISC, GROSS_WEIGHT, NET_WEIGHT, UNITS_PER_PARCEL, UNIT_VOLUME, APPL_TO_ITEM_ENTRY, SHORTCUT_DIMENSION_1_CODE, SHORTCUT_DIMENSION_2_CODE, CUSTOMER_PRICE_GROUP, JOB_NO, WORK_TYPE_CODE, SHIPMENT_NO, SHIPMENT_LINE_NO, BILL_TO_CUSTOMER_NO, ORDER_NO, INV_DISCOUNT_AMOUNT, ORDER_LINE_NO, DROP_SHIPMENT, BILLTO_CUSTOMER_NO, GEN_BUS_POSTING_GROUP, GEN_PROD_POSTING_GROUP, VAT_CALCULATION_TYPE, TRANSACTION_TYPE, TRANSPORT_METHOD, ATTACHED_TO_LINE_NO, EXIT_POINT, AREA, TRANSACTION_SPECIFICATION, TAX_CATEGORY, TAX_AREA_CODE, TAX_LIABLE, TAX_GROUP_CODE, VAT_CLAUSE_CODE, VAT_BUS_POSTING_GROUP, VAT_PROD_POSTING_GROUP, BLANKET_ORDER_NO, BLANKET_ORDER_LINE_NO, VAT_BASE_AMOUNT, UNIT_COST, SYSTEM_CREATED_ENTRY, LINE_AMOUNT, VAT_DIFFERENCE, SYSTEMCREATED_ENTRY, VAT_IDENTIFIER, IC_PARTNER_REF_TYPE, IC_PARTNER_REFERENCE, PREPAYMENT_LINE, IC_PARTNER_CODE, POSTING_DATE, DIMENSION_SET_ID, JOB_TASK_NO, JOB_CONTRACT_ENTRY_NO, PMT_DISCOUNT_AMOUNT, DEFERRAL_CODE, LINE_DISCOUNT_CALCULATION, VARIANT_CODE, BIN_CODE, QTY_PER_UNIT_OF_MEASURE, UNIT_OF_MEASURE_CODE, QUANTITY_BASE, FA_POSTING_DATE, DEPRECIATION_BOOK_CODE, DEPR_UNTIL_FA_POSTING_DATE, DUPLICATE_IN_DEPRECIATION_BOOK, USE_DUPLICATION_LIST, RESPONSIBILITY_CENTER, CROSS_REFERENCE_NO, UNIT_OF_MEASURE_CROSS_REF, CROSS_REFERENCE_TYPE, CROSS_REFERENCE_TYPE_NO, CROSSREFERENCE_NO, ITEM_CATEGORY_CODE, NONSTOCK, PURCHASING_CODE, CROSSREFERENCE_TYPE, PRODUCT_GROUP_CODE, CROSSREFERENCE_TYPE_NO, APPL_FROM_ITEM_ENTRY, RETURN_REASON_CODE, ALLOW_LINE_DISC, CUSTOMER_DISC_GROUP, PMT_DISC_GIVEN_AMOUNT, EC, EC_DIFFERENCE, COD_CADENA, MURANO_CODE, PROMOCIONES_POR, PRICE_DESCRIPTION, MIGRATION_LOT_NO, NO_ALBARAN_VENTA, PMT_DISC_GIVEN_AMOUNT_OLD, COMISIONES_POR, CODIGO_EMBALAJE, NO_LINEA_ALBARAN_VENTA, CANTIDAD_EMBALAJE, COD_VENDEDOR_1, CANTIDAD_UNIDADES, COD_VENDEDOR_2, IDPIRPF_IRPF_GROUP, COD_VENDEDOR_3, CANTIDAD_KILOS, IDPIRPF_IRPF_AMOUNT, IDPIRPF_IRPF, NO_PRESENTACION, COM_1, IDPIRPF_IRPF_BASE_AMOUNT, COM_2, DESCRIPCION_PRESENTACION, COM_3, IDPVUM_QUANTITY, OBSERVACIONES, MOTIVO_DEVOLUCION, IDPVUM_UNIT_OF_MEASURE_CODE, DTO_1, SERVICIO, TIPO_DTO_2, IDPVUM_UNIT_PRICE, IDPVUM_PRICE_IN_VUM, DTO_2, PRECIO_PUNTO_VERDE_CDAD, UNIDAD_MEDIDA_PUNTO_VERDE, IDPVUM_VUM_PER_UNIT, TIPO_DTO_3, CERRADO, IMPORTE_PUNTO_VERDE, DTO_3, GRUPO_RESIDUOS, TIPO_DTO_4, TEMPQTY, PRECIO_RESIDUOS_CDAD, DTO_4, ORIGINAL_QUANTITY, UNIDAD_MEDIDA_RESIDUOS, TIPO_DTO_5, ORIGINAL_QUANTITY_UMV, IMPORTE_RESIDUOS, IDPGND_SIG_AMOUNT, DTO_5, IDPGND_SIG_RATE, NEGRILLA, INCOME_TAX_RETENTION_CODE, IDPGND_SIG, BASE_RAPPEL, INCOME_TAX_RETENTION, IDPGND_POSTING_DATE_SHIPMENT, IMPORTE_PROVISIONADO, INCOME_TAX_BASE, IDPGND_SHIPMENT_DATE_SHIPMENT, IMPORTE_DESPROVISIONADO, SALESPERSON_CODE, COMMISSION_SALESPERSON, IDPGND_REQ_DEL_DATE_SHIPMENT, NO_CUENTA_PROVISION_VENTA, 2ND_SALESPERSON_CODE, NO_CUENTA_PROVISION_CLIENTE, IDPGND_PACKAGING_FORMAT_NO, CLAIM_CODE, COMMISSION_2ND_SALESPERSON, IF_OR_TYPE, SPECIAL_LINE_TYPE, W_ITEM_ENTRIES, IF_UNIT_PRICE_CODE, SALES_SHIPMENT_NO, IF_NUM_BOXES_NEEDED, REAL_SHIPMENT_DATE, SALES_SHIPMENT_LINE_NO, IF_NUM_CONT_NEEDED, CREATION_DATE, TARIFF_NO, IF_DUN14, PLATES_SHIPPED, VAT_BREAKDOWN, TEC_DES_EMPRESA, EDI_POSITION, TEC_ID_INGESTA, Q_CONFIRMADA_RECADV, TYPE_BREAKDOWN, CADASTRAL_REFERENCE, RECADCV_QUANTITY, TEC_TS_INGESTA, TEC_TS_STAGING, EDI_POSITION_SUBLINE, PROPERTY_SITUATION, GLN, TEC_TS_INTEGRACION_B, PLASTIC_LINE, EDI_PRICE, EDI_DISCOUNT) AS tec_hash,
                date(tec_ts_ingesta) as tec_fec_inicio
            from {{ ref('sales_invoice_line_batch') }}
        ) s
        on t.tec_cod_vigencia = 1
            and 1=1
        when matched and t.tec_hash <> s.tec_hash then
            update set
                tec_cod_vigencia = 0,
                tec_fec_fin = case
                    when s.tec_fec_inicio = t.tec_fec_inicio then s.tec_fec_inicio
                    else dateadd(day, -1, s.tec_fec_inicio)
                end;
        {% endif %}"
    ],
    post_hook=[
        "{% set log_ref = source('support_param', 'INSERT_LOGS') %}{% set asociados = var('empresas', []) %}{% for a in asociados %}
            {% set src_ref = source('bronze_' ~ a, 'COOPECARN_SALES_INVOICE_LINE') %}
            -- Sella ÚNICAMENTE el batch (tec_id_ingesta) que está procesando la view {{ ref('sales_invoice_line_batch_' ~ a) }}
            update {{ log_ref }} l
            set tec_ts_integracion_b = current_timestamp()
            where l.tec_ts_integracion_b is null
              and l.start_watermark <> l.end_watermark
              and upper(l.database)   = upper('{{ src_ref.database }}')
              and upper(l.schema)     = upper('{{ src_ref.schema }}')
              and upper(l.table_name) = upper('{{ src_ref.identifier }}')
              and exists (
                  select 1
                  from {{ ref('sales_invoice_line_batch_' ~ a) }} v
                  where v.tec_id_ingesta = l.tec_id_ingesta
              );
        {% endfor %}"
    ]
) }}

